class Solution:
    def finalElement(self, nums):
        memo = {}

        def solve(state, alice_turn):
            if len(state) == 1:
                return state[0]
            key = (state, alice_turn)
            if key in memo:
                return memo[key]
            m = len(state)
            best = None
            for l in range(m):
                for r in range(l, m):
                    if r - l + 1 >= m:
                        continue
                    new_state = state[:l] + state[r + 1:]
                    val = solve(new_state, not alice_turn)
                    if best is None:
                        best = val
                    elif alice_turn:
                        best = max(best, val)
                    else:
                        best = min(best, val)
            memo[key] = best
            return best

        return solve(tuple(nums), True)

